47	
48		-- ===========================================================================
49	  -- Simulation Task and Status Management
50		-- ===========================================================================
51		type		T_SIM_BOOLVEC						is array(integer range <>) of boolean;
52	
53		subtype T_SIM_TEST_ID						is integer range -1 to 1023;
54		subtype T_SIM_TEST_NAME					is string(1 to 256);
55		subtype T_SIM_PROCESS_ID				is natural range 0 to 1023;
56		subtype T_SIM_PROCESS_NAME			is string(1 to 64);
57		subtype T_SIM_PROCESS_INSTNAME	is string(1 to 256);
58		type		T_SIM_PROCESS_ID_VECTOR	is array(natural range <>) of T_SIM_PROCESS_ID;
59	
