61			SIM_TEST_STATUS_CREATED,
62			SIM_TEST_STATUS_ACTIVE,
63			SIM_TEST_STATUS_ENDED,
64			SIM_TEST_STATUS_ZOMBI
65		);
66	
67		type T_SIM_PROCESS_STATUS is (
68			SIM_PROCESS_STATUS_ACTIVE,
69			SIM_PROCESS_STATUS_ENDED
70		);
71	
72		type T_SIM_TEST is record
73			ID									: T_SIM_TEST_ID;
74			Name								: T_SIM_TEST_NAME;
75			Status							: T_SIM_TEST_STATUS;
76			ProcessIDs					: T_SIM_PROCESS_ID_VECTOR(T_SIM_PROCESS_ID);
77			ProcessCount				: T_SIM_PROCESS_ID;
78			ActiveProcessCount	: T_SIM_PROCESS_ID;
79		end record;
80		type T_SIM_TEST_VECTOR	is array(integer range <>) of T_SIM_TEST;
81	
82		type T_SIM_PROCESS is record
83			ID						: T_SIM_PROCESS_ID;
84			TestID				: T_SIM_TEST_ID;
85			Name					: T_SIM_PROCESS_NAME;
86			Status				: T_SIM_PROCESS_STATUS;
87			IsLowPriority	: boolean;
88		end record;
89		type T_SIM_PROCESS_VECTOR is array(natural range <>) of T_SIM_PROCESS;
90	
91		constant C_SIM_DEFAULT_TEST_ID		: T_SIM_TEST_ID		:= -1;
92		constant C_SIM_DEFAULT_TEST_NAME	: string					:= "Default test";
93	
94		-- ===========================================================================
95		-- Random Numbers
96		-- ===========================================================================
97		type T_SIM_RAND_SEED is record
98			Seed1	: integer;
99			Seed2	: integer;
100		end record;
101	
102		procedure randInitializeSeed(Seed : inout T_SIM_RAND_SEED);
103		procedure randInitializeSeed(Seed : inout T_SIM_RAND_SEED; SeedValue : in T_SIM_RAND_SEED);
104		procedure randInitializeSeed(Seed : inout T_SIM_RAND_SEED; SeedVector : in T_INTVEC);
105		procedure randInitializeSeed(Seed : inout T_SIM_RAND_SEED; SeedVector : in string);
106		function	randInitializeSeed return T_SIM_RAND_SEED;
107		function	randInitializeSeed(SeedValue : T_SIM_RAND_SEED) return T_SIM_RAND_SEED;
108		function	randInitializeSeed(SeedVector : T_INTVEC) return T_SIM_RAND_SEED;
109		function	randInitializeSeed(SeedVector : string) return T_SIM_RAND_SEED;
110	
111	
112		-- Uniform distributed random values
113		-- ===========================================================================
114		procedure randUniformDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL);
115		procedure randUniformDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out integer; Minimum : integer; Maximum : integer);
116		procedure randUniformDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL; Minimum : REAL; Maximum : REAL);
117	
118		-- Normal / Gaussian distributed random values
119		-- ===========================================================================
120		procedure randNormalDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL; StandardDeviation : REAL := 1.0; Mean : REAL := 0.0);
121		procedure randNormalDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out integer; StandardDeviation : in REAL; Mean : in REAL; Minimum : in integer; Maximum : in integer);
122		procedure randNormalDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL; StandardDeviation : in REAL; Mean : in REAL; Minimum : in REAL; Maximum : in REAL);
123	
124		-- Poisson distributed random values
125		-- ===========================================================================
126		procedure randPoissonDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL; Mean : in REAL);
127		procedure randPoissonDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out integer; Mean : in REAL; Minimum : in integer; Maximum : in integer);
128		procedure randPoissonDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL; Mean : in REAL; Minimum : in REAL; Maximum : in REAL);
129	
130		-- ===========================================================================
131		-- Clock Generation
132		-- ===========================================================================
133		-- type T_PERCENT is INTEGER'range units
134		type T_PERCENT is range integer'low to INTEGER'high units
135			ppb;
136			ppm			= 1000 ppb;
137			permil	= 1000 ppm;
138			percent	= 10 permil;
139			one			= 100 percent;
140		end units;
141		subtype T_WANDER		is T_PERCENT range -1 one to 1 one;
142		subtype T_DUTYCYCLE	is T_PERCENT range	0 ppb to 1 one;
143	
144		type T_DEGREE is range integer'low to INTEGER'high units
145			second;
146			minute	= 60 second;
147			deg			= 60 minute;
148		end units;
149		subtype T_PHASE is T_DEGREE range	-360 deg to 360 deg;
150	
151		function ite(cond : boolean; value1 : T_DEGREE; value2 : T_DEGREE) return T_DEGREE;
152	end package;
153	
154	
155	package body sim_types is
156		function ite(cond : boolean; value1 : T_DEGREE; value2 : T_DEGREE) return T_DEGREE is
157		begin
158			if cond then
159				return value1;
160			else
161				return value2;
162			end if;
163		end function;
164	
165		-- ===========================================================================
166		-- Random Numbers
167		-- ===========================================================================
168		constant MAX_SEED1_VALUE		: positive	:= 2147483562;
169		constant MAX_SEED2_VALUE		: positive	:= 2147483398;
170	
171		function randGenerateInitialSeed return T_SIM_RAND_SEED is
172		begin
173			return (
174				Seed1 => 5,
175				Seed2 => 3423
176			);
177		end function;
178	
179		function randBoundSeed(SeedValue : in T_SIM_RAND_SEED) return T_SIM_RAND_SEED is
180		begin
181			return (
182				Seed1	=> (SeedValue.Seed1 - 1 mod MAX_SEED1_VALUE) + 1,
183				Seed2	=> (SeedValue.Seed2 - 1 mod MAX_SEED2_VALUE) + 1
184			);
185		end function;
186	
187		procedure randInitializeSeed(Seed : inout T_SIM_RAND_SEED) is
188		begin
189			Seed	:= randGenerateInitialSeed;
190		end procedure;
191	
192		procedure randInitializeSeed(Seed : inout T_SIM_RAND_SEED; SeedValue : in T_SIM_RAND_SEED) is
193		begin
194			Seed	:= randBoundSeed(SeedValue);
195		end procedure;
196	
197		procedure randInitializeSeed(Seed : inout T_SIM_RAND_SEED; SeedVector : in T_INTVEC) is
198		begin
199			if (SeedVector'length = 0) then
200				Seed	:= randGenerateInitialSeed;
201			elsif (SeedVector'length = 1) then
202				Seed	:= randBoundSeed(T_SIM_RAND_SEED'(
203					Seed1 => SeedVector(0),
204					Seed2 => 92346
205				));
206			elsif (SeedVector'length = 2) then
207				Seed	:= randBoundSeed(T_SIM_RAND_SEED'(
208					Seed1 => SeedVector(0),
209					Seed2 => SeedVector(1)
210				));
211			else
212				-- FIXME:
213				-- Seed.Seed1	:= SeedVector(0);
214				-- Seed.Seed2	:= SeedVector(1);
215			end if;
216		end procedure;
217	
218		procedure randInitializeSeed(Seed : inout T_SIM_RAND_SEED; SeedVector : in string) is
219		begin
220			if (SeedVector'length = 0) then
221				Seed	:= randGenerateInitialSeed;
222			elsif (SeedVector'length = 1) then
223				Seed	:= T_SIM_RAND_SEED'(
224					Seed1 => character'pos(SeedVector(1)),
225					Seed2 => 39834
226				);
227			elsif (SeedVector'length = 2) then
228				Seed	:= T_SIM_RAND_SEED'(
229					Seed1 => character'pos(SeedVector(1)),
230					Seed2 => character'pos(SeedVector(2))
231				);
232			else
233				-- FIXME:
234				-- Seed.Seed1	:= CHARACTER'pos(SeedVector(0));
235				-- Seed.Seed2	:= CHARACTER'pos(SeedVector(1));
236			end if;
237		end procedure;
238	
239		function randInitializeSeed return T_SIM_RAND_SEED is
240		begin
241			return randGenerateInitialSeed;
242		end function;
243	
244		function randInitializeSeed(SeedValue : T_SIM_RAND_SEED) return T_SIM_RAND_SEED is
245		begin
246			return randBoundSeed(SeedValue);
247		end function;
248	
249		function randInitializeSeed(SeedVector : T_INTVEC) return T_SIM_RAND_SEED is
250			variable Result		: T_SIM_RAND_SEED;
251		begin
252			randInitializeSeed(Result, SeedVector);
253			return Result;
254		end function;
255	
256		function randInitializeSeed(SeedVector : string) return T_SIM_RAND_SEED is
257			variable Result		: T_SIM_RAND_SEED;
258		begin
259			randInitializeSeed(Result, SeedVector);
260			return Result;
261		end function;
262	
263		-- ===========================================================================
264		-- Uniform distributed random values
265		-- ===========================================================================
266		procedure randUniformDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL) is
267		begin
268			ieee.math_real.Uniform(Seed.Seed1, Seed.Seed2, Value);
269		end procedure;
270	
271		procedure randUniformDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out integer; Minimum : integer; Maximum : integer) is
272			variable rand : REAL;
273		begin
274			if Maximum < Minimum then			report "randUniformDistributedValue: Maximum must be greater than Minimum."	severity FAILURE;		end if;
275			ieee.math_real.Uniform(Seed.Seed1, Seed.Seed2, rand);
276			Value := scale(rand, Minimum, Maximum);
277		end procedure;
278	
279		procedure randUniformDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL; Minimum : REAL; Maximum : REAL) is
280			variable rand : REAL;
281		begin
282			if Maximum < Minimum then			report "randUniformDistributedValue: Maximum must be greater than Minimum."	severity FAILURE;		end if;
283			ieee.math_real.Uniform(Seed.Seed1, Seed.Seed2, rand);
284			Value := scale(rand, Minimum, Maximum);
285		end procedure;
286	
287		-- ===========================================================================
288		-- Normal / Gaussian distributed random values
289		-- ===========================================================================
290		procedure randNormalDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL; StandardDeviation : REAL := 1.0; Mean : REAL := 0.0) is
291			variable rand1 : REAL;
292			variable rand2 : REAL;
293		begin
294			if StandardDeviation < 0.0 then	report "randNormalDistributedValue: Standard deviation must be >= 0.0"			severity FAILURE;		end if;
295			-- Box Muller transformation
296			ieee.math_real.Uniform(Seed.Seed1, Seed.Seed2, rand1);
297			ieee.math_real.Uniform(Seed.Seed1, Seed.Seed2, rand2);
298			--													standard normal distribution: mean 0, variance 1
299			Value := StandardDeviation * (sqrt(-2.0 * log(rand1)) * cos(MATH_2_PI * rand2)) + Mean;
300		end procedure;
301	
302		procedure randNormalDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out integer; StandardDeviation : in REAL; Mean : in REAL; Minimum : in integer; Maximum : in integer) is
303			variable rand_real		: REAL;
304			variable rand_int			: integer;
305		begin
306			if Maximum < Minimum then			report "randNormalDistributedValue: Maximum must be greater than Minimum."	severity FAILURE;		end if;
307			if StandardDeviation < 0.0 then	report "randNormalDistributedValue: Standard deviation must be >= 0.0"			severity FAILURE;		end if;
308			while TRUE loop
309				randNormalDistributedValue(Seed, rand_real, StandardDeviation, Mean);
310				rand_int	:= integer(round(rand_real));
311				exit when ((Minimum <= rand_int) and (rand_int <= Maximum));
312			end loop;
313			Value := rand_int;
314		end procedure;
315	
316		procedure randNormalDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL; StandardDeviation : in REAL; Mean : in REAL; Minimum : in REAL; Maximum : in REAL) is
317			variable rand		: REAL;
318		begin
319			if Maximum < Minimum then			report "randNormalDistributedValue: Maximum must be greater than Minimum."	severity FAILURE;		end if;
320			if StandardDeviation < 0.0 then	report "randNormalDistributedValue: Standard deviation must be >= 0.0"			severity FAILURE;		end if;
321			while TRUE loop
322				randNormalDistributedValue(Seed, rand, StandardDeviation, Mean);
323				exit when ((Minimum <= rand) and (rand <= Maximum));
324			end loop;
325			Value := rand;
326		end procedure;
327	
328		-- ===========================================================================
329		-- Poisson distributed random values
330		-- ===========================================================================
331		procedure randPoissonDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL; Mean : in REAL) is
332			variable Product	: Real;
333			variable Bound		: Real;
334			variable rand			: Real;
335			variable Result		: Real;
336		begin
337			Product	:= 1.0;
338			Result	:= 0.0;
339			Bound		:= exp(-1.0 * Mean);
340			if ((Mean <= 0.0) or (Bound <= 0.0)) then
341				report "randPoissonDistributedValue: Mean must be greater than 0.0." severity FAILURE;
342				return;
343			end if;
344	
345			while (Product >= Bound) loop
346				ieee.math_real.Uniform(Seed.Seed1, Seed.Seed2, rand);
347				Product		:= Product * rand;
348				Result		:= Result + 1.0;
349			end loop;
350			Value	:= Result;
351		end procedure;
352	
353		procedure randPoissonDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out integer; Mean : in REAL; Minimum : in integer; Maximum : in integer) is
354			variable rand_real		: REAL;
355			variable rand_int			: integer;
356		begin
357			if Maximum < Minimum then			report "randPoissonDistributedValue: Maximum must be greater than Minimum."	severity FAILURE;		end if;
358			while TRUE loop
359				randPoissonDistributedValue(Seed, rand_real, Mean);
360				rand_int	:= integer(round(rand_real));
361				exit when ((Minimum <= rand_int) and (rand_int <= Maximum));
362			end loop;
363			Value := rand_int;
364		end procedure;
365	
366		procedure randPoissonDistributedValue(Seed : inout T_SIM_RAND_SEED; Value : out REAL; Mean : in REAL; Minimum : in REAL; Maximum : in REAL) is
367			variable rand		: REAL;
368		begin
369			if Maximum < Minimum then			report "randPoissonDistributedValue: Maximum must be greater than Minimum."	severity FAILURE;		end if;
370			while TRUE loop
371				randPoissonDistributedValue(Seed, rand, Mean);
372				exit when ((Minimum <= rand) and (rand <= Maximum));
373			end loop;
374			Value := rand;
375		end procedure;
376	end package body;
377

