421			variable Index								: natural;
422	
423			constant ClockAfterRun_cy			: positive	:= 5;
424		begin
425			Clock		<= '1';
426			randInitializeSeed(Seed);
427	
428			while not simIsStopped(TestID) loop
429				ieee.math_real.Uniform(Seed.Seed1, Seed.Seed2, rand);
430				Index		:= scale(rand, 0, JitterDistribution'length * 10) mod JitterDistribution'length;
431				randNormalDistributedValue(Seed, rand, JitterDistribution(Index).StandardDeviation, JitterDistribution(Index).Mean, -1.0, 1.0);
432	
433				Jitter := JitterAsFactor * rand;
434				Debug		<= rand;
435	
436				-- Debug		<= integer(rand * 256.0 + 256.0);
437				wait for TimeHigh + (Period * Jitter);
438				Clock		<= '0';
439				wait for TimeLow + (Period * Jitter);
440				Clock		<= '1';
441			end loop;
442			-- create N more cycles to allow other processes to recognize the stop condition (clock after run)
443			for i in 1 to ClockAfterRun_cy loop
444				wait for TimeHigh;
445				Clock		<= '0';
446				wait for TimeLow;
447				Clock		<= '1';
448			end loop;
449			Clock		<= '0';
450		end procedure;
