722		function "*" (Wave : T_SIM_WAVEFORM; Times : natural) return T_SIM_WAVEFORM is
723			variable Result		: T_SIM_WAVEFORM(0 to Wave'length * Times - 1);
724		begin
725			for i in 0 to Times - 1 loop
