731		function ">" (Wave : T_SIM_WAVEFORM; Offset : time) return T_SIM_WAVEFORM is
732		begin
733			return (Wave(Wave'low) + Offset) & Wave(Wave'low + 1 to Wave'high);
734		end function;
735	
736		function "<" (Wave : T_SIM_WAVEFORM; Offset : time) return T_SIM_WAVEFORM is
737			variable Result		: T_SIM_WAVEFORM(Wave'range);
738			variable TimePos	: time;
739		begin
740			report "Has bugs" severity ERROR;
741			TimePos := 0 fs;
742			for i in Wave'range loop
743				TimePos	:= TimePos + Wave(i);
744				if TimePos > Offset then
745					return (TimePos - Offset) & Wave(i + 1 to Wave'high);
746				end if;
747			end loop;
748			return (0 => 0 fs);
749		end function;
