958				Result(i).Delay		:= Delay;
959				Result(i).Value		:= slvv(i);
960			end loop;
961			return Result;
962		end function;
963	
964		-- predefined common waveforms
965		function simGenerateWaveform_Reset(constant Pause : time := 0 ns; ResetPulse : time := 10 ns) return T_SIM_WAVEFORM is
966			variable p  : time;
967			variable rp : time;
968		begin
969			-- WORKAROUND: for Mentor QuestaSim/ModelSim
970			--	Version:	10.4c
971			--	Issue:
972			--		return (0 => Pause, 1 => ResetPulse); always evaluates to (0 ns, 10 ns),
973			--		regardless of the passed function parameters
974			--	Bugfix:
975			--		The bugfix will be included in 10.5a, but this workaround must be
976			--		present until Altera updates the embedded ModelSim Altera Edition.
977			p  := Pause;
978			rp := ResetPulse;
979			return (0 => p, 1 => rp);
980		end function;
981	end package body;
982

